#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn rust_logo_creates_icon() {
        let icon = rust_logo();
        assert_eq!(icon.icon_size(), 24.0);
    }

    #[test]
    fn rust_gear_creates_icon() {
        let icon = rust_gear();
        assert_eq!(icon.icon_size(), 24.0);
    }

    #[test]
    fn rust_logo_complete_creates_icon() {
        let icon = rust_logo_complete();
        assert_eq!(icon.icon_size(), 24.0);
    }

    #[test]
    fn rust_logo_can_be_resized() {
        let icon = rust_logo().size(48.0);
        assert_eq!(icon.icon_size(), 48.0);
    }

    #[test]
    fn ferris_creates_icon() {
        let icon = ferris();
        assert_eq!(icon.icon_size(), 24.0);
    }
}
